bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    if (!partition_valid_ || !checksum_valid_)
    {
        return false;
    }

    auto it = assets_.find(name);
    if (it == assets_.end())
    {
        return false;
    }

    const auto &asset = it->second;

    // Check if the asset data is within bounds
    if (asset.offset + asset.size > partition_->size)
    {
        ESP_LOGE(TAG, "Asset %s data is out of bounds", name.c_str());
        return false;
    }

    // Get the pointer to the asset data
    ptr = const_cast<void*>(static_cast<const void*>(mmap_root_ + asset.offset));

    // Verify the magic number (assuming the first 4 bytes of asset data is the magic number)
    uint32_t magic = *(uint32_t*)ptr;
    if (magic != 0x41535345) // "ASSE" in little-endian
    {
        ESP_LOGE(TAG, "Invalid magic number for asset %s: 0x%08x", name.c_str(), magic);
        return false;
    }

    // Set the size to exclude the magic number header
    size = asset.size - sizeof(uint32_t);

    return true;
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    if (state >= 0 && state < sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0]))
    {
        return STATE_STRINGS[state];
    }
    return STATE_STRINGS[0]; // Return "unknown" for invalid states
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    // Define valid transitions based on state flow
    switch (from) {
        case kDeviceStateUnknown:
            // Can only go to starting state
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // Can only go to wifi_configuring state
            return to == kDeviceStateWifiConfiguring;

        case kDeviceStateWifiConfiguring:
            // Can go to idle state or directly to fatal_error
            return (to == kDeviceStateIdle) || (to == kDeviceStateFatalError);

        case kDeviceStateIdle:
            // Can go to connecting, listening, or fatal_error
            return (to == kDeviceStateConnecting) || 
                   (to == kDeviceStateListening) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateConnecting:
            // Can go to listening or fatal_error
            return (to == kDeviceStateListening) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateListening:
            // Can go to speaking, upgrading, or fatal_error
            return (to == kDeviceStateSpeaking) || 
                   (to == kDeviceStateUpgrading) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateSpeaking:
            // Can go back to idle or fatal_error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateUpgrading:
            // Can go to activating or fatal_error
            return (to == kDeviceStateActivating) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // Can go to audio_testing or fatal_error
            return (to == kDeviceStateAudioTesting) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateAudioTesting:
            // Can go back to idle or fatal_error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // Can only go to itself (no further transitions)
            return false;

        default:
            // Invalid from state
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_.load();

    // No-op if already in the target state
    if (old_state == new_state)
    {
        return true;
    }

    // Validate transition
    if (!IsValidTransition(old_state, new_state))
    {
        ESP_LOGW(TAG, "Invalid state transition: %s -> %s",
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform transition
    current_state_.store(new_state);
    ESP_LOGI(TAG, "State: %s -> %s",
             GetStateName(old_state), GetStateName(new_state));

    // Notify callback
    NotifyStateChange(old_state, new_state);
    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(mutex_);

    // Generate a unique ID for the new listener
    int listener_id = next_listener_id_++;

    // Store the listener with its ID and callback
    listeners_.emplace_back(listener_id, callback);

    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listener_id)
{
    std::lock_guard<std::mutex> lock(mutex_);
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
            [listener_id](const std::pair<int, StateCallback>& item) {
                return item.first == listener_id;
            }),
        listeners_.end()
    );
}

void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state)
{
    std::lock_guard<std::mutex> lock(mutex_);

    // Create a copy of listeners to avoid issues if callbacks modify the list
    auto listeners_copy = listeners_;

    // Notify all listeners
    for (const auto &listener : listeners_copy)
    {
        try
        {
            listener.second(old_state, new_state);
        }
        catch (...)
        {
            // Silently ignore exceptions in callbacks to prevent crashes
            // In a real system, you might want to log this
        }
    }
}

