Ota::Ota()
{
    // Initialize serial number from eFuse user data block
    uint8_t efuse_serial[12]; // ESP32 eFuse serial number is 12 bytes
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_USER_DATA, efuse_serial, 96);

    if (err == ESP_OK)
    {
        // Convert binary data to hex string
        char serial_buffer[25]; // 12 bytes * 2 hex chars + null terminator
        for (int i = 0; i < 12; i++)
        {
            sprintf(&serial_buffer[i*2], "%02x", efuse_serial[i]);
        }
        serial_number_ = std::string(serial_buffer);
        has_serial_number_ = !serial_number_.empty();

        if (has_serial_number_)
        {
            ESP_LOGI(TAG, "Serial number read from eFuse: %s", serial_number_.c_str());
        }
        else
        {
            ESP_LOGW(TAG, "Serial number is empty");
        }
    }
    else
    {
        ESP_LOGW(TAG, "Failed to read serial number from eFuse: %s", esp_err_to_name(err));
        has_serial_number_ = false;
    }
}

