std::unique_ptr<Http> Ota::SetupHttp()
{
    auto http = std::make_unique<Http>();

    // Set device identification headers
    auto &board = Board::GetInstance();
    http->SetHeader("X-Device-Id", board.GetDeviceId());
    http->SetHeader("X-Device-Type", board.GetDeviceType());

    // Set user agent
    auto app_desc = esp_app_get_description();
    http->SetHeader("User-Agent", std::string("ESP32-") + app_desc->version);

    // Set language
    http->SetHeader("Accept-Language", lang_config_get_current_lang());

    // Set content type
    http->SetHeader("Content-Type", "application/json");

    // Set serial number if available
    if (has_serial_number_)
    {
        http->SetHeader("X-Serial-Number", serial_number_);
    }

    return http;
}

esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.back() != '/')
    {
        url += "/version";
    }
    else
    {
        url += "version";
    }

    auto http = SetupHttp();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection for version check");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, code: %d", status_code);
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response from version check");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Version check response: %s", response.c_str());

    cJSON *json = cJSON_Parse(response.c_str());
    if (json == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for new version
    cJSON *version = cJSON_GetObjectItem(json, "version");
    if (version && cJSON_IsString(version))
    {
        std::string new_version = cJSON_GetStringValue(version);
        if (!new_version.empty())
        {
            auto current_version = esp_app_get_description()->version;
            ESP_LOGI(TAG, "Current version: %s, Available version: %s", current_version, new_version.c_str());

            if (IsNewVersionAvailable(current_version, new_version))
            {
                firmware_url_ = "";
                cJSON *download_url = cJSON_GetObjectItem(json, "download_url");
                if (download_url && cJSON_IsString(download_url))
                {
                    firmware_url_ = cJSON_GetStringValue(download_url);
                }

                if (firmware_url_.empty())
                {
                    ESP_LOGE(TAG, "No download URL provided in version response");
                    cJSON_Delete(json);
                    return ESP_FAIL;
                }

                ESP_LOGI(TAG, "New firmware available at: %s", firmware_url_.c_str());
            }
        }
    }

    // Handle activation challenge
    cJSON *challenge = cJSON_GetObjectItem(json, "challenge");
    if (challenge && cJSON_IsString(challenge))
    {
        activation_challenge_ = cJSON_GetStringValue(challenge);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge: %s", activation_challenge_.c_str());
    }
    else
    {
        has_activation_challenge_ = false;
    }

    // Handle MQTT configuration
    cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config && cJSON_IsObject(mqtt_config))
    {
        Settings settings("mqtt", true);

        cJSON *server = cJSON_GetObjectItem(mqtt_config, "server");
        if (server && cJSON_IsString(server))
        {
            settings.SetString("server", cJSON_GetStringValue(server));
        }

        cJSON *port = cJSON_GetObjectItem(mqtt_config, "port");
        if (port && cJSON_IsNumber(port))
        {
            settings.SetInt("port", cJSON_GetNumberValue(port));
        }

        cJSON *username = cJSON_GetObjectItem(mqtt_config, "username");
        if (username && cJSON_IsString(username))
        {
            settings.SetString("username", cJSON_GetStringValue(username));
        }

        cJSON *password = cJSON_GetObjectItem(mqtt_config, "password");
        if (password && cJSON_IsString(password))
        {
            settings.SetString("password", cJSON_GetStringValue(password));
        }

        cJSON *topic = cJSON_GetObjectItem(mqtt_config, "topic");
        if (topic && cJSON_IsString(topic))
        {
            settings.SetString("topic", cJSON_GetStringValue(topic));
        }

        settings.Save();
        ESP_LOGI(TAG, "MQTT configuration updated");
    }

    cJSON_Delete(json);
    return ESP_OK;
}

void Ota::MarkCurrentVersionValid()
{
    ESP_LOGI(TAG, "Marking current version as valid");

    // Get the currently running partition
    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL)
    {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (strcmp(running_partition->label, "factory") == 0)
    {
        ESP_LOGI(TAG, "Skipping validation for factory partition");
        return;
    }

    // Mark the current partition as valid
    esp_err_t err = esp_ota_mark_app_valid_cancel_rollback();
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to mark current version as valid: %s", esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Successfully marked current version as valid");
}

bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    ESP_LOGI(TAG, "Starting firmware upgrade from %s", firmware_url.c_str());

    // Create HTTP client
    auto &board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto http = network->CreateHttp(0);

    // Set up headers
    auto user_agent = SystemInfo::GetUserAgent();
    http->SetHeader("User-Agent", user_agent);
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/octet-stream");

    // Open connection
    if (!http->Open("GET", firmware_url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for upgrade, code=0x%x", last_error);
        return false;
    }

    // Get content length
    auto content_length = http->GetContentLength();
    if (content_length <= 0)
    {
        ESP_LOGE(TAG, "Invalid content length: %ld", content_length);
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Firmware size: %ld bytes", content_length);

    // Start OTA update
    esp_err_t err = ESP_OK;
    esp_ota_handle_t ota_handle;
    const esp_partition_t *partition = esp_ota_get_next_update_partition(NULL);

    if (partition == NULL)
    {
        ESP_LOGE(TAG, "No OTA partition available");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition: %s", partition->label);

    err = esp_ota_begin(partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_begin failed: %s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Download and write firmware
    uint8_t *buffer = new uint8_t[4096];
    if (!buffer)
    {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        http->Close();
        esp_ota_end(ota_handle);
        return false;
    }

    size_t total_received = 0;
    uint32_t last_update = 0;
    size_t speed = 0;
    uint32_t start_time = esp_timer_get_time() / 1000; // milliseconds

    while (total_received < content_length)
    {
        size_t to_read = std::min(static_cast<size_t>(4096), static_cast<size_t>(content_length - total_received));
        int bytes_read = http->Read(buffer, to_read);

        if (bytes_read <= 0)
        {
            ESP_LOGE(TAG, "Failed to read from HTTP stream");
            delete[] buffer;
            http->Close();
            esp_ota_end(ota_handle);
            return false;
        }

        err = esp_ota_write(ota_handle, buffer, bytes_read);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "esp_ota_write failed: %s", esp_err_to_name(err));
            delete[] buffer;
            http->Close();
            esp_ota_end(ota_handle);
            return false;
        }

        total_received += bytes_read;

        // Calculate speed every 100ms
        uint32_t current_time = esp_timer_get_time() / 1000;
        if (current_time - last_update >= 100 || total_received >= content_length)
        {
            uint32_t time_diff = current_time - start_time;
            if (time_diff > 0)
            {
                speed = (total_received * 1000) / time_diff; // bytes per second
            }

            int progress = (total_received * 100) / content_length;
            if (callback)
            {
                callback(progress, speed);
            }

            last_update = current_time;
        }
    }

    delete[] buffer;
    http->Close();

    // Verify and end OTA
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_end failed: %s", esp_err_to_name(err));
        return false;
    }

    // Validate the new firmware
    err = esp_ota_set_boot_partition(partition);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> result;
    if (version.empty()) {
        return result;
    }

    size_t start = 0;
    size_t end = 0;

    // Split by dots and convert each part to integer
    while (end != std::string::npos) {
        end = version.find('.', start);
        std::string part = version.substr(start, end - start);

        // Convert substring to integer and add to result
        try {
            int num = std::stoi(part);
            result.push_back(num);
        } catch (const std::exception&) {
            // If conversion fails, treat as 0 or skip
            result.push_back(0);
        }

        start = end + 1;
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    auto current = ParseVersion(currentVersion);
    auto newVer = ParseVersion(newVersion);

    // Compare version segments one by one
    size_t minSize = std::min(current.size(), newVer.size());

    for (size_t i = 0; i < minSize; ++i)
    {
        if (newVer[i] > current[i])
        {
            return true;
        }
        else if (newVer[i] < current[i])
        {
            return false;
        }
        // If equal, continue to next segment
    }

    // If all compared segments are equal, the version with more segments is newer
    // For example, 1.2.3.4 is newer than 1.2.3
    return newVer.size() > current.size();
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        // Return empty JSON object if no serial number
        return "{}";
    }

    // Create JSON payload with required fields
    cJSON *root = cJSON_CreateObject();
    if (root == NULL)
    {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge
    if (has_activation_challenge_)
    {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    }

    // Add timestamp (current time)
    cJSON_AddNumberToObject(root, "timestamp", time(NULL));

    // Generate HMAC-SHA256 signature
    std::string payload_str = cJSON_PrintUnformatted(root);
    if (payload_str.empty())
    {
        cJSON_Delete(root);
        return "{}";
    }

    // Generate signature using HMAC-SHA256
    uint8_t hmac_result[32]; // SHA256 produces 32 bytes
    esp_err_t err = ESP_FAIL;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware HMAC if supported
    err = esp_hmac_calculate(ESP_HMAC_SHA256, 
                            (const uint8_t*)payload_str.c_str(),
                            payload_str.length(),
                            (const uint8_t*)CONFIG_ACTIVATION_KEY,
                            strlen(CONFIG_ACTIVATION_KEY),
                            hmac_result);
#else
    // Fallback to software implementation or skip signing
    // For now, we'll skip HMAC calculation if hardware support is not available
    ESP_LOGW(TAG, "HMAC hardware support not available, skipping signature");
#endif

    if (err == ESP_OK)
    {
        // Convert HMAC result to hex string
        char hmac_hex[65] = {0}; // 32 bytes * 2 + 1 for null terminator
        for (int i = 0; i < 32; i++)
        {
            sprintf(&hmac_hex[i*2], "%02x", hmac_result[i]);
        }
        cJSON_AddStringToObject(root, "signature", hmac_hex);
    }
    else
    {
        ESP_LOGW(TAG, "Failed to calculate HMAC, skipping signature");
    }

    // Clean up and return JSON string
    std::string result = cJSON_PrintUnformatted(root);
    cJSON_Delete(root);

    return result;
}

esp_err_t Ota::Activate()
{
    if (!has_serial_number_)
    {
        ESP_LOGI(TAG, "No serial number available, skipping activation");
        return ESP_OK;
    }

    if (!has_activation_challenge_)
    {
        ESP_LOGE(TAG, "No activation challenge available");
        return ESP_ERR_INVALID_STATE;
    }

    std::string url = GetCheckVersionUrl();
    if (url.length() < 10)
    {
        ESP_LOGE(TAG, "Activation URL is not properly set");
        return ESP_ERR_INVALID_ARG;
    }

    // Append "/activate" to the base URL for activation endpoint
    if (url.back() != '/')
    {
        url += '/';
    }
    url += "activate";

    auto http = SetupHttp();

    // Set up the activation payload
    std::string payload = GetActivationPayload();
    http->SetContent(std::move(payload));

    // Set Content-Type header for JSON payload
    http->SetHeader("Content-Type", "application/json");

    if (!http->Open("POST", url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to activate, status code: %d", status_code);
        return status_code;
    }

    std::string response = http->ReadAll();
    http->Close();

    // Parse the JSON response to check activation result
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

    cJSON *success = cJSON_GetObjectItem(root, "success");
    if (cJSON_IsBool(success))
    {
        if (!cJSON_IsTrue(success))
        {
            cJSON *error = cJSON_GetObjectItem(root, "error");
            if (cJSON_IsString(error))
            {
                ESP_LOGE(TAG, "Activation failed: %s", error->valuestring);
            }
            else
            {
                ESP_LOGE(TAG, "Activation failed with unknown error");
            }
            cJSON_Delete(root);
            return ESP_FAIL;
        }
    }
    else
    {
        ESP_LOGE(TAG, "Invalid activation response format");
        cJSON_Delete(root);
        return ESP_ERR_INVALID_RESPONSE;
    }

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Activation successful");
    return ESP_OK;
}

Settings::~Settings()
{
    if (nvs_handle_ != 0)
    {
        // Only commit if we have unsaved changes and the namespace was opened for writing
        if (read_write_ && dirty_)
        {
            ESP_ERROR_CHECK(nvs_commit(nvs_handle_));
        }
        nvs_close(nvs_handle_);
        nvs_handle_ = 0;
    }
}

std::string Settings::GetString(const std::string &key, const std::string &default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);
    if (err != ESP_OK)
    {
        return default_value;
    }

    if (required_size == 0)
    {
        return "";
    }

    std::string value(required_size - 1, '\0'); // -1 to exclude null terminator
    err = nvs_get_str(nvs_handle_, key.c_str(), &value[0], &required_size);
    if (err != ESP_OK)
    {
        return default_value;
    }

    return value;
}

void Settings::SetString(const std::string &key, const std::string &value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_str(nvs_handle_, key.c_str(), value.c_str()));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

int32_t Settings::GetInt(const std::string &key, int32_t default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    int32_t value;
    if (nvs_get_i32(nvs_handle_, key.c_str(), &value) != ESP_OK)
    {
        return default_value;
    }
    return value;
}

void Settings::SetInt(const std::string &key, int32_t value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_i32(nvs_handle_, key.c_str(), value));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

bool Settings::GetBool(const std::string &key, bool default_value)
{
    if (nvs_handle_ == 0)
    {
        return default_value;
    }

    uint8_t value;
    if (nvs_get_u8(nvs_handle_, key.c_str(), &value) != ESP_OK)
    {
        return default_value;
    }
    return value != 0;
}

void Settings::SetBool(const std::string &key, bool value)
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_set_u8(nvs_handle_, key.c_str(), value ? 1 : 0));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

void Settings::EraseKey(const std::string &key)
{
    if (read_write_)
    {
        // Use ESP_ERROR_CHECK to handle potential errors from nvs_erase_key
        // This will automatically log errors and panic if needed
        esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());
        if (err == ESP_OK)
        {
            dirty_ = true;
        }
        else if (err == ESP_ERR_NVS_KEY_NOT_FOUND)
        {
            // Key doesn't exist, but this is not an error condition
            // We still mark as dirty to maintain consistency with other operations
            // though technically no change was made
        }
        else
        {
            // Handle other possible errors
            ESP_LOGE(TAG, "Failed to erase key %s: %s", key.c_str(), esp_err_to_name(err));
        }
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

void Settings::EraseAll()
{
    if (read_write_)
    {
        ESP_ERROR_CHECK(nvs_erase_all(nvs_handle_));
        dirty_ = true;
    }
    else
    {
        ESP_LOGW(TAG, "Namespace %s is not open for writing", ns_.c_str());
    }
}

size_t SystemInfo::GetFlashSize()
{
    size_t flash_size = 0;
    esp_flash_t* flash = NULL;

    // Get the default flash chip handle
    esp_err_t err = esp_flash_init(&flash);
    if (err != ESP_OK) {
        return 0;
    }

    // Get the flash size
    err = esp_flash_get_size(flash, &flash_size);
    if (err != ESP_OK) {
        return 0;
    }

    return flash_size;
}

std::string SystemInfo::GetMacAddress()
{
    uint8_t mac[6];
    esp_err_t err = esp_efuse_mac_get_default(mac);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to get MAC address: %s", esp_err_to_name(err));
        return "";
    }

    // Format MAC address as XX:XX:XX:XX:XX:XX
    char mac_str[18]; // 17 characters + null terminator
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(mac_str);
}

std::string SystemInfo::GetUserAgent()
{
    const esp_app_desc_t *app_desc = esp_app_get_description();
    if (app_desc == NULL)
    {
        return std::string(CONFIG_IDF_TARGET) + "/unknown";
    }

    char user_agent[128];
    snprintf(user_agent, sizeof(user_agent), "%s/%s", CONFIG_IDF_TARGET, app_desc->version);
    return std::string(user_agent);
}

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    // Get initial task statistics
    TaskStatus_t *pxTaskStatusArray;
    UBaseType_t uxArraySize;
    volatile UBaseType_t uxHigherPriorityReadyTasks;

    // Get the number of tasks
    uxArraySize = uxTaskGetNumberOfTasks();

    // Allocate memory for task status array
    pxTaskStatusArray = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * uxArraySize);
    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status array");
        return ESP_FAIL;
    }

    // Get current task status
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &uxHigherPriorityReadyTasks);

    // Store initial run time counters
    uint32_t *ulPreviousTotalRunTime = (uint32_t *)malloc(sizeof(uint32_t) * uxArraySize);
    if (ulPreviousTotalRunTime == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for previous run time");
        free(pxTaskStatusArray);
        return ESP_FAIL;
    }

    // Initialize previous run times
    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        ulPreviousTotalRunTime[x] = pxTaskStatusArray[x].ulRunTimeCounter;
    }

    // Wait for the specified time interval
    vTaskDelay(xTicksToWait);

    // Get updated task status
    uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &uxHigherPriorityReadyTasks);

    // Calculate CPU usage for each task
    char buffer[1000];
    int pos = snprintf(buffer, sizeof(buffer), "Task CPU Usage:\n");

    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        uint32_t ulTotalRunTime = pxTaskStatusArray[x].ulRunTimeCounter - ulPreviousTotalRunTime[x];
        uint32_t ulTotalTime = xTicksToWait * configTICK_RATE_HZ; // Total time in ticks

        // Calculate percentage (avoid division by zero)
        uint32_t ulPercentage = 0;
        if (ulTotalTime > 0) {
            ulPercentage = (ulTotalRunTime * 100) / ulTotalTime;
        }

        // Format task information
        pos += snprintf(buffer + pos, sizeof(buffer) - pos, 
                       "%s: %lu%% (%lu/%lu)\n", 
                       pxTaskStatusArray[x].pcTaskName,
                       ulPercentage,
                       ulTotalRunTime,
                       ulTotalTime);
    }

    ESP_LOGI(TAG, "%s", buffer);

    // Free allocated memory
    free(pxTaskStatusArray);
    free(ulPreviousTotalRunTime);

    return ESP_OK;
}

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    char buffer[1000];
    vTaskGetRunTimeStats(buffer);
    ESP_LOGI(TAG, "Task CPU usage: \n%s", buffer);
    return ESP_OK;
}

