FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : window_size_(window_size)
{
    // Calculate angular frequency
    float omega = 2.0f * M_PI * frequency;

    // Calculate filter coefficients for Goertzel algorithm
    // These are derived from the Goertzel algorithm for frequency detection
    filter_coefficient_ = 2.0f * std::cos(omega);
    sin_coefficient_ = std::sin(omega);
    cos_coefficient_ = std::cos(omega);

    // Initialize state buffer with zeros
    state_buffer_.clear();
    state_buffer_.resize(2, 0.0f);
}

void FrequencyDetector::Reset()
{
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::ProcessSample(float sample)
{
    if (state_buffer_.size() < 2)
    {
        // Initialize buffer if needed
        state_buffer_.resize(2, 0.0f);
    }

    // Apply the second-order IIR filter difference equation
    // s[n] = filter_coefficient_ * s[n-1] - s[n-2] + sample
    float new_sample = filter_coefficient_ * state_buffer_[1] - state_buffer_[0] + sample;

    // Update the state buffer (circular buffer)
    state_buffer_[0] = state_buffer_[1];
    state_buffer_[1] = new_sample;
}

float FrequencyDetector::GetAmplitude() const
{
    if (state_buffer_.size() < 2)
    {
        return 0.0f;
    }

    // Get the last two samples (S[-1] and S[-2])
    auto it = state_buffer_.begin();
    float s_minus_1 = *it++;  // S[-1]
    float s_minus_2 = *it;    // S[-2]

    // Apply the Goertzel algorithm to compute real and imaginary parts
    // Using the recurrence relation: y[n] = cos_coefficient * y[n-1] - y[n-2] + sample
    float real = cos_coefficient_ * s_minus_1 - s_minus_2 + 0.0f;  // Assuming current sample is 0 for amplitude calculation
    float imag = sin_coefficient_ * s_minus_1;

    // Calculate amplitude as sqrt(real^2 + imag^2)
    float amplitude = std::sqrt(real * real + imag * imag);

    // Normalize by half the window size as per Goertzel algorithm convention
    return amplitude / (static_cast<float>(window_size_) * 0.5f);
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                                           size_t bit_rate, size_t window_size)
    : sample_rate_(sample_rate),
      mark_frequency_(mark_frequency),
      space_frequency_(space_frequency),
      bit_rate_(bit_rate),
      window_size_(window_size)
{
    // Validate that sample rate is divisible by bit rate
    if (sample_rate_ % bit_rate_ != 0)
    {
        ESP_LOGW(kLogTag, "Sample rate (%zu) is not divisible by bit rate (%zu)", sample_rate_, bit_rate_);
    }

    // Calculate samples per bit
    samples_per_bit_ = sample_rate_ / bit_rate_;

    // Create frequency detectors for mark and space frequencies
    mark_detector_ = std::make_unique<FrequencyDetector>(
        static_cast<float>(mark_frequency_) / static_cast<float>(sample_rate_), window_size_);
    space_detector_ = std::make_unique<FrequencyDetector>(
        static_cast<float>(space_frequency_) / static_cast<float>(sample_rate_), window_size_);

    // Set up input buffer size
    input_buffer_size_ = window_size_;
    input_buffer_.resize(input_buffer_size_);

    // Initialize output sample counter
    output_sample_count_ = 0;
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples)
{
    std::vector<float> probabilities;

    // Process samples in chunks of input_buffer_size_
    for (size_t i = 0; i < samples.size(); i += input_buffer_size_)
    {
        // Ensure we have enough samples for a complete window
        if (i + input_buffer_size_ > samples.size())
        {
            break;
        }

        // Reset detectors for new window
        mark_detector_->Reset();
        space_detector_->Reset();

        // Process all samples in the current window
        for (size_t j = 0; j < input_buffer_size_; ++j)
        {
            float sample = samples[i + j];
            mark_detector_->ProcessSample(sample);
            space_detector_->ProcessSample(sample);
        }

        // Get amplitudes from both detectors
        float mark_amplitude = mark_detector_->GetAmplitude();
        float space_amplitude = space_detector_->GetAmplitude();

        // Calculate probability: if mark amplitude is significantly higher than space amplitude,
        // it's likely a mark tone (probability close to 1.0)
        // if space amplitude is higher, it's likely a space tone (probability close to 0.0)
        float probability = 0.0f;
        if (mark_amplitude + space_amplitude > 0.0f)
        {
            probability = mark_amplitude / (mark_amplitude + space_amplitude);
        }

        probabilities.push_back(probability);
    }

    return probabilities;
}

AudioDataBuffer::AudioDataBuffer()
    : current_state_(DataReceptionState::kInactive),
