void PwmBacklight::SetBrightnessImpl(uint8_t brightness)
{
    // LEDC resolution set to 10bits, thus: 100% = 1023
    uint32_t duty_cycle = (1023 * brightness) / 100;
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
}

Board::Board()
{
    // Try to load existing UUID from NVS storage
    nvs_handle_t nvs_handle;
    esp_err_t err = nvs_open("storage", NVS_READWRITE, &nvs_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open NVS");
        // Generate a new UUID if we can't access NVS
        uuid_ = GenerateUuid();
        return;
    }

    size_t required_size = 0;
    err = nvs_get_str(nvs_handle, "uuid", nullptr, &required_size);

    if (err == ESP_ERR_NVS_NOT_FOUND) {
        // No UUID found, generate a new one
        uuid_ = GenerateUuid();
        // Save the new UUID to NVS
        err = nvs_set_str(nvs_handle, "uuid", uuid_.c_str());
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to save UUID to NVS");
        }
    } else if (err == ESP_OK && required_size > 0) {
        // UUID exists, load it
        char* uuid_buffer = new char[required_size];
        err = nvs_get_str(nvs_handle, "uuid", uuid_buffer, &required_size);
        if (err == ESP_OK) {
            uuid_ = std::string(uuid_buffer);
        } else {
            ESP_LOGE(TAG, "Failed to read UUID from NVS");
            uuid_ = GenerateUuid();
        }
        delete[] uuid_buffer;
    } else {
        ESP_LOGE(TAG, "Error reading UUID from NVS");
        uuid_ = GenerateUuid();
    }

    nvs_close(nvs_handle);
}

std::string Board::GenerateUuid()
{
    uint8_t uuid[16];

    // Generate 16 bytes of random data
    esp_fill_random(uuid, sizeof(uuid));

    // Set the version bits (bits 12-15 of the time_hi_and_version field)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set the variant bits (bits 6-7 of the clock_seq_hi_res field)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuid_str[37]; // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

Display *Board::GetDisplay()
{
    // Check if display is enabled in settings
    Settings settings("display", true);
    bool display_enabled = settings.GetBool("enabled", false);

    if (!display_enabled) {
        static NoDisplay display;
        return &display;
    }

    // Try to initialize OLED display if available
    static OledDisplay oled_display;
    if (oled_display.IsInitialized()) {
        return &oled_display;
    }

    // Fallback to NoDisplay if no valid display is found
    static NoDisplay no_display;
    return &no_display;
}

