}

std::string Board::GetSystemInfoJson()
{
    // Hardware info
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    // Flash size
    size_t flash_size;
    esp_flash_get_size(NULL, &flash_size);

    // MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);

    // OTA boot partition
    const esp_partition_t* boot_partition = esp_ota_get_boot_partition();
    char ota_partition_label[16];
    if (boot_partition && boot_partition->label[0] != '\0') {
        strncpy(ota_partition_label, boot_partition->label, sizeof(ota_partition_label) - 1);
        ota_partition_label[sizeof(ota_partition_label) - 1] = '\0';
    } else {
        strcpy(ota_partition_label, "unknown");
    }

    // Free heap size
    size_t min_free_heap = esp_get_free_heap_size();

    // Constructing JSON manually
    std::string json = "{";

    // Add hardware info
    json += "\"hardware\":{";
    json += "\"chip_model\":\"ESP32\",";
    json += "\"chip_cores\":" + std::to_string(chip_info.cores) + ",";
    json += "\"chip_revision\":" + std::to_string(chip_info.revision) + ",";
    json += "\"flash_size\":" + std::to_string(flash_size) + ",";
    json += "\"mac_address\":\"" +
            std::to_string(mac[0], 16) + ":" +
            std::to_string(mac[1], 16) + ":" +
            std::to_string(mac[2], 16) + ":" +
            std::to_string(mac[3], 16) + ":" +
            std::to_string(mac[4], 16) + ":" +
            std::to_string(mac[5], 16) + "\"";
    json += "},";

    // Add app metadata
    json += "\"application\":{";
    json += "\"name\":\"" APP_NAME "\",";
    json += "\"version\":\"" APP_VERSION "\",";
    json += "\"compile_time\":\"" COMPILE_TIME "\"";
    json += "},";

    // Add partition info
    json += "\"partition\":{";
    json += "\"boot_label\":\"" + std::string(ota_partition_label) + "\"";
    json += "},";

    // Add runtime info
    json += "\"runtime\":{";
    json += "\"min_free_heap\":" + std::to_string(min_free_heap) + ",";
    json += "\"uuid\":\"" + uuid_ + "\"";
    json += "}";

    json += "}";

    return json;
}

