const char *WifiBoard::GetNetworkStateIcon()
{
    auto &wifi = WifiManager::GetInstance();

    // Check if in configuration mode first
    if (in_config_mode_) {
        return "wifi-configure";  // Or similar icon for config mode
    }

    // Check connection status
    if (!wifi.IsConnected()) {
        return "wifi-off";  // Icon for disconnected
    }

    // Get signal strength
    int rssi = wifi.GetRssi();

    // Return appropriate icon based on signal strength
    if (rssi >= -60) {
        return "wifi-strong";   // Strong signal
    } else if (rssi >= -70) {
        return "wifi-medium";   // Medium signal
    } else {
        return "wifi-weak";     // Weak signal
    }
}

std::string WifiBoard::GetBoardJson()
{
    auto &board = Board::GetInstance();
    auto &wifi = WifiManager::GetInstance();

    auto root = cJSON_CreateObject();

    // Add board type
    cJSON_AddStringToObject(root, "type", GetBoardType().c_str());

    // Add board name from system info
    auto &sys_info = SystemInfo::GetInstance();
    cJSON_AddStringToObject(root, "name", sys_info.GetDeviceName().c_str());

    // Add MAC address
    uint8_t mac[6];
    esp_efuse_mac_get_default(mac);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac", mac_str);

    // Add Wi-Fi details if not in config mode
    if (!wifi.IsConfigMode()) {
        auto wifi_info = cJSON_CreateObject();

        // Add SSID
        cJSON_AddStringToObject(wifi_info, "ssid", wifi.GetSsid().c_str());

        // Add RSSI
        cJSON_AddNumberToObject(wifi_info, "rssi", wifi.GetRssi());

        // Add channel
        cJSON_AddNumberToObject(wifi_info, "channel", wifi.GetChannel());

        // Add IP address
        auto ip_info = wifi.GetIpInfo();
        if (ip_info.ip.addr != 0) {
            char ip_str[16];
            snprintf(ip_str, sizeof(ip_str), IPSTR, IP2STR(&ip_info.ip));
            cJSON_AddStringToObject(wifi_info, "ip", ip_str);
        }

        cJSON_AddItemToObject(root, "wifi", wifi_info);
    }

    auto str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    auto &wifi_manager = WifiManager::GetInstance();

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            // Configure for maximum power saving
            wifi_manager.SetPowerSave(WIFI_PS_MIN_MODEM);
            break;
        case PowerSaveLevel::BALANCED:
            // Configure for balanced power saving
            wifi_manager.SetPowerSave(WIFI_PS_MAX_MODEM);
            break;
        case PowerSaveLevel::PERFORMANCE:
            // Disable power saving for maximum performance
            wifi_manager.SetPowerSave(WIFI_PS_NONE);
            break;
        default:
            // Default to balanced if unknown level
            wifi_manager.SetPowerSave(WIFI_PS_MAX_MODEM);
            break;
    }
}

std::string WifiBoard::GetDeviceStatusJson()
{
    auto &wifi = WifiManager::GetInstance();
    auto &audio = Board::GetInstance().GetAudioCodec();
    auto &display = Board::GetInstance().GetDisplay();
    auto &power = PowerManager::GetInstance();

    std::string json = "{";

    // Audio speaker volume
    if (audio) {
        json += "\"volume\":" + std::to_string(audio->volume()) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Screen brightness and theme
    if (display) {
        json += "\"brightness\":" + std::to_string(display->brightness()) + ",";
        json += "\"theme\":\"" + display->theme() + "\",";
    } else {
        json += "\"brightness\":0,\"theme\":\"default\",";
    }

    // Battery level and charging state
    json += "\"battery\":" + std::to_string(power.GetBatteryLevel()) + ",";
    json += "\"charging\":" + std::to_string(power.IsCharging() ? 1 : 0) + ",";

    // WiFi network details
    if (!wifi.IsConfigMode()) {
        json += "\"ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"rssi\":" + std::to_string(wifi.GetRssi()) + ",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,";
    }

    // Chip temperature
    json += "\"temperature\":" + std::to_string(SystemInfo::GetChipTemperature()) + ",";

    // Remove trailing comma and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

