SingleLed::SingleLed(gpio_num_t gpio)
{
    // Initialize LED strip configuration
    led_strip_config_t led_strip_cfg = LED_STRIP_DEFAULT_CONFIG(gpio, LED_STRIP_RMT_TIMER, 1);

    // Create LED strip
    esp_err_t ret = led_strip_new_rmt_device(&led_strip_cfg, &led_strip_);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to create LED strip");
        led_strip_ = nullptr;
        return;
    }

    // Initialize default color values
    r_ = 0;
    g_ = 0;
    b_ = 0;

    // Initialize blink counter and interval
    blink_counter_ = 0;
    blink_interval_ms_ = 0;

    // Create blinking timer
    const esp_timer_create_args_t timer_args = {
        .callback = [](void *arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .arg = this,
        .name = "led_blink",
        .dispatch_method = ESP_TIMER_TASK,
        .skip_unhandled_events = true
    };

    ret = esp_timer_create(&timer_args, &blink_timer_);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to create blink timer");
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
        return;
    }

    // Clear the LED initially
    led_strip_clear(led_strip_);
}

SingleLed::~SingleLed()
{
    if (led_strip_ != nullptr) {
        esp_timer_stop(blink_timer_);
        led_strip_del(led_strip_);
        led_strip_ = nullptr;
    }

    if (blink_timer_ != nullptr) {
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }
}

void SingleLed::SetColor(uint8_t r, uint8_t g, uint8_t b)
{
    std::lock_guard<std::mutex> lock(mutex_);
    r_ = r;
    g_ = g;
    b_ = b;
}

void SingleLed::TurnOn()
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);
    esp_timer_stop(blink_timer_);
    led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
    led_strip_refresh(led_strip_);
}

void SingleLed::TurnOff()
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);
    esp_timer_stop(blink_timer_);
    led_strip_clear(led_strip_);
}

void SingleLed::StartBlinkTask(int times, int interval_ms)
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);

    // Set the blink counter - if times is BLINK_INFINITE (-1), we keep blinking forever
    if (times == BLINK_INFINITE)
    {
        blink_counter_ = BLINK_INFINITE;
    }
    else
    {
        // Each blink consists of on/off cycle, so we need twice the number of times
        blink_counter_ = times * 2;
    }

    // Configure and start the timer with the specified interval
    esp_timer_stop(blink_timer_);
    ESP_ERROR_CHECK(esp_timer_start_periodic(blink_timer_, interval_ms * 1000)); // Convert ms to microseconds
}

void SingleLed::OnBlinkTimer()
{
    if (led_strip_ == nullptr)
    {
        return;
    }

    std::lock_guard<std::mutex> lock(mutex_);

    if (blink_counter_ > 0)
    {
        blink_counter_--;

        // Toggle LED state
        if (blink_counter_ % 2 == 0)
        {
            // Turn on
            led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
            led_strip_refresh(led_strip_);
        }
        else
        {
            // Turn off
            led_strip_clear(led_strip_);
        }
    }
    else
    {
        // Stop the timer when blinking is complete
        esp_timer_stop(blink_timer_);
    }
}

